      expect(attempts).toBe(1);
      expect(result.error).toContain('Delivery failed after 1 attempts');
    });
  });

  describe('custom transport', () => {
    it('should use custom transport when set', async () => {
      const captured: Array<{ to: string; body: string }> = [];
      adapter.setTransport(async (message) => {
        captured.push({ to: message.to, body: message.body });
      });

      await adapter.send(makePayload());
      expect(captured).toHaveLength(1);
      expect(captured[0]!.to).toBe('+15551234567');
      // Default in-memory store should NOT have the message since we replaced transport
      expect(adapter.getSentMessages()).toHaveLength(0);
    });
  });
